    71→const getColor = (layer, name, intervals, customRamp) => {
    72→    const chosenColors = layer
    73→        ? head((layer.thematic.colors || layer.thematic.additionalColors || []).filter(c => c.name === name))
    74→        : customRamp
    75→            ? head([ customRamp, ...standardColors].filter(c => c.name === name))
    76→            : head(standardColors.filter(c => c.name === name));
    77→    if (chosenColors && (isString(chosenColors.colors) || chosenColors.colors.length >= 2)) {
    78→        return {
    79→            ramp: "custom",
    80→            colors: chroma.scale(chosenColors.colors).colors(intervals).join(',')
    81→        };
    82→    }
    83→    return { ramp: name };
    84→};
