    86→const mapParams = (layer, params) => {
    87→    const configParams = layer.thematic && layer.thematic.params || [];
    88→    const otherParams = layer.thematic && layer.thematic.fieldAsParam && ['field'] || [];
    89→    return Object.keys(params).reduce((previous, key) => {
    90→        if (isViewParam(key, [...configParams, ...otherParams])) {
    91→            return assign(previous, addViewParam(previous.viewparams, key, params[key]));
    92→        }
