    94→            return assign(previous, getColor(layer, params[key], params.intervals || 5));
    95→        }
    96→        if (key === 'classification') {
    97→            return assign(previous, getCustomClassification(params[key]));
    98→        }
    99→        if (key === 'attribute') {
   100→            return assign(previous, {
   101→                attribute: layer.thematic && layer.thematic.fieldAsParam ? params[key] : params.field
   102→            });
   103→        }
   104→        if (key === 'field' && layer.thematic && !layer.thematic.fieldAsParam) {
   105→            return previous;
   106→        }
