   109→                [key]: -1
   110→            });
   111→        }
   112→        if (key === 'strokeOn') {
   113→            return previous;
   114→        }
   115→        return assign(previous, {
   116→            [key]: params[key]
   117→        });
   118→    }, {});
   119→};
