   155→        return rule.LineSymbolizer.Stroke && rule.LineSymbolizer.Stroke.CssParameter
   156→            && rule.LineSymbolizer.Stroke.CssParameter.$ || '#808080'; // OGC default color
   157→    }
   158→    if (rule.PointSymbolizer) {
